template<class T>
class Stack {
private:
 T arr[100];
 int top;
public:
 Stack() { top = -1; }
 void push(T item) {
 if (top >= 99) throw "Overflow";
 arr[++top] = item;
 }
 T pop() {
 if (top < 0) throw "Underflow";
 return arr[top--];
 }
 bool isEmpty() { return top == -1; }
};

// Usage
int main() {
 Stack<int> intStack;
 Stack<float> floatStack;
 Stack<string> strStack;
 intStack.push(10);
 floatStack.push(3.14);
 return 0;
}

template<class T, int MAXSIZE = 100>
class Array {
private:
 T data[MAXSIZE];
 int size;
public:
 Array() { size = 0; }
 void add(T item) {
 if (size < MAXSIZE) data[size++] = item;
 }
 T get(int index) {
 if (index >= 0 && index < size) return data[index];
 throw "Invalid index";
 }
 int getSize() { return size; }
};

// Usage
int main() {
 Array<int, 50> smallArr; // Size 50
 Array<int> defaultArr; // Default size 100
 Array<double, 200> largeArr;
 return 0;
}

template<class T>
class Calculator {
public:
 T add(T a, T b) { return a + b; }
};

// Full specialization for char*
template<>
class Calculator<char*> {
public:
 char* add(char* a, char* b) {
 char* result = new char[strlen(a) + strlen(b) + 1];
 strcpy(result, a);
 strcat(result, b);
 return result;
 }
};

// Usage
int main() {
 Calculator<int> intCalc;
 Calculator<char*> strCalc;
 cout << intCalc.add(5, 3); // Output: 8
 cout << strCalc.add("Hello", "World"); // Output: HelloWorld
 return 0;
}

template<class T>
class PointerHolder {
 T value;
public:
 void set(T v) { value = v; }
 T get() { return value; }
};

// Partial specialization for pointers
template<class T>
class PointerHolder<T*> {
 T* ptr;
public:
 void set(T* p) { ptr = p; }
 T* get() { return ptr; }
 void display() { cout << *ptr; }
};

// Usage
int main() {
 int x = 10;
 PointerHolder<int> ph1; // Regular version
 PointerHolder<int*> ph2; // Pointer version
 ph1.set(x);
 ph2.set(&x);
 ph2.display(); // Outputs: 10
 return 0;
}

class Container {
 int data[10];
 int size;
public:
 Container() { size = 0; }

 // Template member function
 template<class T>
 void set(T item, int index) {
 if (index >= 0 && index < 10) 
 data[index] = static_cast<int>(item);
 }

 template<class T>
 T get(int index) {
 return static_cast<T>(data[index]);
 }

 void add(int item) { if(size < 10) data[size++] = item; }
};

// Usage
int main() {
 Container c;
 c.add(100);
 double d = c.get<double>(0); // Converts int to double
 string s = c.get<string>(0); // Converts int to string
 return 0;
}
